import React from "react";
import { FiSearch, FiBell, FiUser } from "react-icons/fi";

export default function Header() {
  return (
    <header className="w-full h-20 bg-white shadow-md rounded-xl mb-4 px-6 py-4 flex justify-between sticky top-0 z-50">

      {/* LEFT : Search Bar */}
      <div className="flex items-center bg-gray-100 px-4 py-2 rounded-lg w-100">
        <FiSearch className="text-gray-400 mr-2" />
        <input
          type="text"
          placeholder="Search here..."
          className="bg-transparent outline-none w-full text-sm"
        />
      </div>

      {/* RIGHT : Notification + Login */}
      <div className="flex items-center gap-6">
        
        {/* Notification */}
        <div className="relative cursor-pointer">
          <FiBell className="text-2xl text-gray-600" />
          <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs w-4 h-4 flex items-center justify-center rounded-full">
            2
          </span>
        </div>

        {/* Login / Profile */}
        <div className="flex items-center gap-2 cursor-pointer border px-3 py-2 rounded-lg hover:bg-gray-100 bg-[#ff7b00]">
          <FiUser className="text-xl text-gray-600" />
          <span className="text-sm font-medium text-gray-700">
            Login
          </span>
        </div>

      </div>
    </header>
  );
}